import{_ as a,o as i,c as s,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 PFC 电流参考","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 电流参考","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）的第一步，是让输入电流尽量跟交流输入电压同相、同形。电流参考（current reference）就是控制器希望输入电流跟踪的目标波形。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/single-phase-pfc-current-reference.md","filePath":"content/power/concepts/power-electronics/single-phase-pfc-current-reference.md","lastUpdated":null}'),l={name:"content/power/concepts/power-electronics/single-phase-pfc-current-reference.md"};function n(r,e,p,o,c,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="概念-单相-pfc-电流参考" tabindex="-1">概念：单相 PFC 电流参考 <a class="header-anchor" href="#概念-单相-pfc-电流参考" aria-label="Permalink to &quot;概念：单相 PFC 电流参考&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）的第一步，是让输入电流尽量跟交流输入电压同相、同形。电流参考（current reference）就是控制器希望输入电流跟踪的目标波形。</p><p>本节只讲“电流参考怎么长出来”，不讲完整 PFC 电压环、电流环和 PWM 实现。本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-ups-为什么需要它" tabindex="-1">2. UPS 为什么需要它 <a class="header-anchor" href="#_2-ups-为什么需要它" aria-label="Permalink to &quot;2. UPS 为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）前级通常要从交流电网取电。如果输入电流畸变严重或与电压不同相，就会带来：</p><ul><li>功率因数低，视在功率变大。</li><li>电网谐波电流增加。</li><li>前级整流和母线电容电流应力增大。</li></ul><p>PFC 的目标是让电网看到的负载更接近电阻性负载。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>如果一个负载像纯电阻，那么电压为正时电流为正，电压为负时电流为负，并且二者同步变化。PFC 电流参考就是让电源前级“装得像电阻”。</p><p>整流后的 Boost PFC 功率级实际只处理正向电感电流，但从交流输入侧看，电流应当跟 <code>vac</code> 同相。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>若希望输入功率为 <code>P</code>，电网均方根值（root mean square / RMS）为 <code>Vrms</code>，可以用等效电导：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>G = P / Vrms^2</span></span>
<span class="line"><span>i_ref(t) = G * v_ac(t)</span></span></code></pre></div><p>这样平均功率为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pavg = mean(v_ac(t) * i_ref(t))</span></span></code></pre></div><p>在理想情况下，电流和电压同相，功率因数接近 1。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>一个仿真任务是运行 <code>single_phase_pfc_current_reference.py</code>，观察 <code>vac</code>、<code>|vac|</code>、<code>iref</code> 和瞬时功率之间的关系：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_reference.py</span></span></code></pre></div><p>对比目标功率：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_reference.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">target</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">power </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_current_ref_500w.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_current_reference.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">target</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">power </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_current_ref_1500w.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察：</p><ul><li>交流输入电压 <code>vac</code> 是正负交替的正弦。</li><li>整流电压 <code>|vac|</code> 是 Boost PFC 功率级看到的正半波形状。</li><li>电流参考 <code>iref</code> 与 <code>vac</code> 同相。</li><li>瞬时功率 <code>p(t)</code> 有两倍工频脉动，但平均功率接近目标功率。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实固件中，电流参考通常不是孤立公式，而是由以下信号共同决定：</p><ul><li>电压环输出的功率或电流幅值指令。</li><li>交流电压采样或锁相环（phase-locked loop / PLL）提供的相位/单位正弦。</li><li>前馈和限幅逻辑。</li><li>电流环把实际电感电流跟踪到参考值。</li></ul><p>本节只建立 <code>iref</code> 的形状，为后续电压环、电流环和 PLL 做准备。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：PFC 就是把输出母线电压升到 380 V。<br> 正确理解：升压只是功率级功能；PFC 的关键是输入电流形状和相位。</p></li><li><p>错误理解：电流参考越大越好。<br> 正确理解：电流参考幅值由功率需求、输入电压、限流和母线控制共同决定。</p></li><li><p>错误理解：整流后电压是正的，所以交流侧电流也只看正值。<br> 正确理解：从电网侧看，电流仍应与交流电压同相，正负半周都要对应。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释功率因数校正（power factor correction / PFC）电流参考为什么要与 <code>vac</code> 同相。</li><li>能用 <code>G = P / Vrms^2</code> 推出 <code>i_ref = G * vac</code>。</li><li>能在图中指出 <code>vac</code>、<code>|vac|</code>、<code>iref</code> 和 <code>p(t)</code>。</li><li>能解释为什么瞬时功率有脉动，但平均功率接近目标功率。</li><li>能基于图中 PF、RMS 和功率参数准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，<code>Vrms=220 V</code>、<code>P=1000 W</code>，电流 RMS 大约是多少？</li><li>如果目标功率从 500 W 提高到 1500 W，<code>iref</code> 幅值如何变化？</li><li>为什么本节没有直接讲完整电压环？如果电流参考都不会看，直接看双环控制会卡在哪里？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_current_reference.py</code> 看到 <code>iref = G * vac</code> 时功率因数接近 1。公司单相 PFC 代码里的电流参考是直接用输入电压采样生成，还是通过 PLL/单位正弦生成？</li><li>本节用 <code>P / Vrms^2</code> 生成等效电导。真实工程里电流参考幅值通常来自电压环输出、功率指令，还是前馈计算？</li><li>图中瞬时功率有两倍工频脉动。公司工程里母线电压环如何避免跟着二倍频纹波乱调？</li></ul>`,36)])])}const u=a(l,[["render",n]]);export{k as __pageData,u as default};
